            }
            else -> null
        }?.apply {
            addFlags(Intent.FLAG_ACTIVITY_CLEAR_TOP or Intent.FLAG_ACTIVITY_SINGLE_TOP)
        }
    }

    fun handle(activity: Activity, uri: Uri): Boolean {
        val intent = createIntent(activity, uri) ?: return false
        activity.startActivity(intent)
        return true
    }
}

